const BIRD_MODEL_BASE64 = "";
const BIRD_MODEL_BASE64 = "";
// Global Error Logger for web overlay debugging
window.onerror = function(msg, url, line, col, error) {
  const div = document.createElement("div");
  div.style.position = "fixed";
  div.style.bottom = "0";
  div.style.left = "0";
  div.style.width = "100%";
  div.style.background = "rgba(220, 53, 69, 0.95)";
  div.style.color = "white";
  div.style.fontFamily = "monospace";
  div.style.fontSize = "12px";
  div.style.padding = "10px";
  div.style.zIndex = "999999";
  div.style.whiteSpace = "pre-wrap";
  div.style.borderTop = "3px solid #ffc107";
  div.innerText = `[JS Error] ${msg}\nLine: ${line}\nURL: ${url}`;
  document.body.appendChild(div);
};

window.onunhandledrejection = function(event) {
  const div = document.createElement("div");
  div.style.position = "fixed";
  div.style.bottom = "60px";
  div.style.left = "0";
  div.style.width = "100%";
  div.style.background = "rgba(253, 126, 20, 0.95)";
  div.style.color = "white";
  div.style.fontFamily = "monospace";
  div.style.fontSize = "12px";
  div.style.padding = "10px";
  div.style.zIndex = "999999";
  div.style.whiteSpace = "pre-wrap";
  div.style.borderTop = "3px solid #ffc107";
  div.innerText = `[Promise Rejection] ${event.reason}`;
  document.body.appendChild(div);
};

document.addEventListener("DOMContentLoaded", () => {


  const canvas = document.getElementById("birds-canvas");
  if (!canvas) return;

  const container = canvas.parentElement;

  // WebGL Renderer Setup with transparent background
  const renderer = new THREE.WebGLRenderer({
    canvas: canvas,
    alpha: true,
    antialias: true
  });
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));

  // Scene & Camera
  const scene = new THREE.Scene();
  const camera = new THREE.PerspectiveCamera(45, container.clientWidth / container.clientHeight, 1, 1000);
  camera.position.set(0, 0, 100);

  // Atmospheric lighting matching the top-left sun
  const ambientLight = new THREE.AmbientLight(0xffffff, 0.75);
  scene.add(ambientLight);

  const sunLight = new THREE.DirectionalLight(0xfff8e7, 1.2);
  sunLight.position.set(-60, 45, 30);
  scene.add(sunLight);

  const birds = [];
  const boundsX = 85;
  const boundsY = 42;
  const flockSize = 6;

  // Load the pre-made animated GLTF/GLB bird model
  if (typeof THREE.GLTFLoader === "undefined") {
    console.error("THREE.GLTFLoader is undefined! Make sure GLTFLoader.js is loaded correctly.");
    return;
  }

  const loader = new THREE.GLTFLoader();
  loader.load(
    "data:application/octet-stream;base64," + BIRD_MODEL_BASE64,
    (gltf) => {
      const baseModel = gltf.scene;
      const animationClip = gltf.animations[0];

      if (!animationClip) {
        console.warn("No animations found in the GLB model.");
      }

      for (let i = 0; i < flockSize; i++) {
        const birdClone = baseModel.clone();
        
        // Scale down the model (stork/glb models are typically large)
        birdClone.scale.set(0.07, 0.07, 0.07);

        // Distribute birds across the X-axis immediately so they are visible on page load
        const progress = i / flockSize;
        birdClone.position.set(
          -boundsX + progress * 2 * boundsX,
          -boundsY + 0.35 * boundsY + Math.random() * 0.5 * boundsY,
          -35 + Math.random() * 70
        );

        // Movement configuration: 4 fly right, 2 fly left
        const direction = i % 3 !== 0 ? 1 : -1;
        const baseSpeed = 0.12 + Math.random() * 0.08;
        
        const velocity = new THREE.Vector3(
          direction * baseSpeed,
          (Math.random() - 0.5) * 0.02,
          (Math.random() - 0.5) * 0.015
        );

        if (direction === -1) {
          birdClone.rotation.y = Math.PI;
        }

        // Setup individual animation mixer if animations exist
        let mixer = null;
        if (animationClip) {
          mixer = new THREE.AnimationMixer(birdClone);
          const action = mixer.clipAction(animationClip);
          action.time = Math.random() * animationClip.duration;
          mixer.timeScale = 1.0 + (Math.random() - 0.5) * 0.3;
          action.play();
        }

        scene.add(birdClone);
        
        birds.push({
          mesh: birdClone,
          velocity: velocity,
          mixer: mixer,
          wingPhase: Math.random() * Math.PI * 2
        });
      }
    },
    undefined,
    (error) => {
      console.error("Error loading birds.glb model:", error);
    }
  );

  // Resize handler
  function resize() {
    const w = container.clientWidth;
    const h = container.clientHeight;
    renderer.setSize(w, h, false);
    camera.aspect = w / h;
    camera.updateProjectionMatrix();
  }
  window.addEventListener("resize", resize);
  resize();

  // Animation Loop
  const clock = new THREE.Clock();

  function animate() {
    requestAnimationFrame(animate);

    const delta = clock.getDelta();
    const time = clock.getElapsedTime();

    birds.forEach(bird => {
      // Update animations
      if (bird.mixer) {
        bird.mixer.update(delta);
      }

      // Translate position based on velocity vector
      bird.mesh.position.addScaledVector(bird.velocity, 60 * delta);

      // Add a subtle wave bobbing to make flight look organic
      bird.mesh.position.y += Math.sin(time * 1.5 + bird.wingPhase) * 0.012;

      // Update banking and roll dynamically during flight adjustments
      const pitch = bird.velocity.y * 2.5;
      const roll = Math.sin(time * 3 + bird.wingPhase) * 0.05;
      
      if (bird.velocity.x > 0) {
        bird.mesh.rotation.set(pitch, Math.sin(time * 0.15) * 0.04, roll);
      } else {
        bird.mesh.rotation.set(-pitch, Math.PI - Math.sin(time * 0.15) * 0.04, -roll);
      }

      // Wrap around boundary coordinates to keep infinite flock flow
      const padding = 15;
      if (bird.velocity.x > 0 && bird.mesh.position.x > boundsX + padding) {
        bird.mesh.position.x = -boundsX - padding;
        bird.mesh.position.y = -boundsY + 0.3 * boundsY + Math.random() * 0.5 * boundsY;
      } else if (bird.velocity.x < 0 && bird.mesh.position.x < -boundsX - padding) {
        bird.mesh.position.x = boundsX + padding;
        bird.mesh.position.y = -boundsY + 0.3 * boundsY + Math.random() * 0.5 * boundsY;
      }
    });

    renderer.render(scene, camera);
  }

  animate();
});



